svg.script:
(function(){
  var base = (window.location.hostname !== "")
    ? window.location.protocol + "//" + window.location.host
    : "http://erp.localhost:8080";
  if (base === "http://erp.localhost:8080") return;
  var ns = "http://www.w3.org/1999/xlink";
  document.querySelectorAll("a").forEach(function(a){
    var href = a.getAttributeNS(ns, "href") || a.getAttribute("href") || "";
    if (href) a.setAttributeNS(ns, "href", href.replace(/^http:\/\/erp\.localhost:8080/, base));
  });
})();
